const { workflow, Chat } = require('@novu/framework');

const slackNotificationWorkflow = workflow('slack-notification', async (step) => {
  await step.chat(
    'send-to-slack',
    async () => {
      return {
        body: 'Hello from Novu!'
      };
    }
  );
});

module.exports = { slackNotificationWorkflow };

